module top_module(RegDst,Rd,Rt,writereg);input [1:0] RegDst;
input [4:0] Rd;
input [4:0] Rt;
output [4:0] writereg;

wire neg_mux_output = (RegDst == 2'b00);
assign writereg = neg_mux_output ? Rd : (RegDst == 2'b01) ? Rt :
                  (RegDst == 2'b10) ? 5'b11111 :
                  5'b11010;

endmodule
